    this.request = {
      method: req.method,
      url: req.url,
      path: parsedUrl.pathname,
      query: parsedUrl.query,
      headers: { ...req.headers },
      body: null,
      params: {},
    };

    this.response = {
      statusCode: 200,
      headers: {},
      body: null,
      sent: false,
    };

    // Upstream/proxy target configuration
