class Router {
  constructor() {
    this.routes = [];
  }

  addRoute(route) {
    const {
      method = 'ALL',
      path,
      pathPattern,
      upstream,
      plugins = [],
      rateLimit,
      auth,
      ...rest
    } = route;

    this.routes.push({
      method: method.toUpperCase(),
      path,
      pathRegex: pathPattern ? new RegExp(pathPattern) : this.pathToRegex(path),
      upstream,
      plugins,
      rateLimit,
      auth,
      ...rest,
    });
  }

  pathToRegex(pathStr) {
    if (!pathStr) return null;
    const regexStr = pathStr
      .replace(/\/:([^/]+)/g, '/(?<$1>[^/]+)')
      .replace(/\//g, '\\/');
    return new RegExp(`^${regexStr}$`);
  }

  match(method, pathname) {
    for (const route of this.routes) {
      if (route.method !== 'ALL' && route.method !== method.toUpperCase()) {
        continue;
      }

      if (route.pathRegex) {
        const match = pathname.match(route.pathRegex);
        if (match) {
          return { route, params: match.groups || {} };
        }
      }
    }
    return null;
  }

  loadRoutesFromConfig(config) {
    if (config.routes && Array.isArray(config.routes)) {
      for (const route of config.routes) {
        this.addRoute(route);
        console.log(`[Router] Added route: ${route.method || 'ALL'} ${route.path}`);
      }
    }
  }
}

